"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[967299],{419454:e=>{e.exports=JSON.parse('{"tag":{"label":"prefabs","permalink":"/dst-api-webdocs/docs/tags/prefabs","allTagsPath":"/dst-api-webdocs/docs/tags","count":29,"items":[{"id":"game-scripts/prefabs/armor_lavaarena","title":"Armor Lavaarena","description":"Defines and registers multiple armor prefabs for the Lava Arena event with specific builds, tags, and footstep sounds.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_lavaarena"},{"id":"game-scripts/prefabs/beefalo","title":"Beefalo","description":"This component initializes beefalo and beefalo_carry prefabs with assets, loot tables, and helper functions for managing state including domestication, riding, shaving, carrat interactions, bell ownership, mood visualization, combat retargeting, and shadow poop logic with save/load support.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beefalo"},{"id":"game-scripts/prefabs/carnival_food","title":"Carnival Food","description":"Generates a set of carnival-themed food prefabs with configurable nutritional values, perishability, and floating behavior.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/carnival_food"},{"id":"game-scripts/prefabs/explode_small","title":"Explode Small","description":"Creates a non-persistent visual and audio effect for small explosions and related actions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/explode_small"},{"id":"game-scripts/prefabs/grotto_pool_big","title":"Grotto Pool Big","description":"Creates and manages a large grotto pool entity with visual, lighting, and child object placement functionality.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/grotto_pool_big"},{"id":"game-scripts/prefabs/hats","title":"Hats","description":"The hats component defines and manages wearable headgear prefabs in Don\'t Starve Together, providing equip/unequip logic, component integration (armor, fueled, waterproofer, etc.), and hat-specific behaviors like light control, pet followers, and skill-attuned mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hats"},{"id":"game-scripts/prefabs/hermithouse_laundry","title":"Hermithouse Laundry","description":"Factory function that generates prefabs for laundry items used in the Hermithouse environment.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermithouse_laundry"},{"id":"game-scripts/prefabs/lantern_posts_defs","title":"Lantern Posts Defs","description":"Defines configuration structures for lantern post prefabs, including lighting, sound, and behavior parameters.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lantern_posts_defs"},{"id":"game-scripts/prefabs/lavaarena_creature_spawn_fx","title":"Lavaarena Creature Spawn Fx","description":"Creates visual and audio effects for lava arena creature spawning, including teleport smoke and spark particles, with instance-limited audio volume scaling and server/client separation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_creature_spawn_fx"},{"id":"game-scripts/prefabs/lavaarena_portal","title":"Lavaarena Portal","description":"Defines the prefabs for the Lava Arena portal structure, including its static mesh, keyhole, and activation effect.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_portal"},{"id":"game-scripts/prefabs/mandrake_inactive","title":"Mandrake Inactive","description":"Represents an inactive mandrake plant prefab that becomes edible and triggers sleep effects when eaten raw or cooked.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/mandrake_inactive"},{"id":"game-scripts/map/static_layouts/monkeyisland_retrofitsmall_02","title":"Monkeyisland Retrofitsmall 02","description":"Static map layout configuration for a monkey island area in DST, defining background tiles, objects, and structural elements via Tiled JSON.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/monkeyisland_retrofitsmall_02"},{"id":"game-scripts/prefabs/moonglass_stalactites","title":"Moonglass Stalactites","description":"Generates three prefabs for non-blocking moonglass stalactite decorative entities used in world environments.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/moonglass_stalactites"},{"id":"game-scripts/map/static_layouts/pigguards","title":"Pigguards","description":"Defines a Tiled map layout for pig guard enclosures, specifying background tiles and object placements for walls and pig torches.","permalink":"/dst-api-webdocs/docs/game-scripts/map/static_layouts/pigguards"},{"id":"game-scripts/prefablist","title":"Prefablist","description":"A static array containing the string names of all registered prefab entities available in the game build.","permalink":"/dst-api-webdocs/docs/game-scripts/prefablist"},{"id":"game-scripts/prefabskin","title":"Prefabskin","description":"This component defines initialization and cleanup functions for applying and removing skins on various prefabs including structures, items, weapons, armor, hats, and pets, managing animation overrides, visual effects, sound effects, component states, and event listeners, with a factory function to register skin prefabs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabskin"},{"id":"game-scripts/prefabskins","title":"Prefabskins","description":"This module defines the PREFAB_SKINS table mapping prefabs to skin identifiers, along with a selection blacklist and a reverse lookup table for skin IDs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabskins"},{"id":"game-scripts/prefabswaps","title":"Prefabswaps","description":"Manages configurable prefab substitutions used during world generation, supporting primary/non-primary variants, location-based exclusions, and customization-controlled prefabs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabswaps"},{"id":"game-scripts/prefabs/quagmire_oldstructures","title":"Quagmire Oldstructures","description":"Defines prefabs for Quagmire-era decorative and structural props (e.g., rubble, carriage, clocktower) used in the old structures theme.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_oldstructures"},{"id":"game-scripts/prefabs/quagmire_plantables","title":"Quagmire Plantables","description":"Definesprefabs and logic for Quagmire crops, including seeds, planted stages, leaves, soil visuals, raw products, and cooked products.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/quagmire_plantables"},{"id":"game-scripts/prefabs/rocks","title":"Rocks","description":"Defines prefabs for various rock types in the game, each with unique mining behavior, loot tables, and visual appearances.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rocks"},{"id":"game-scripts/prefabs/skilltree_wormwood","title":"Skilltree Wormwood","description":"Defines the complete skill tree configuration and data structure for the Wormwood character in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/skilltree_wormwood"},{"id":"game-scripts/prefabs/skinprefabs","title":"Skinprefabs","description":"This module registers cosmetic skin prefabs for characters, items, structures, and tools using CreatePrefabSkin, defining initialization callbacks, rarity levels, and skin-specific behavior including bloom effects and color changes.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/skinprefabs"},{"id":"game-scripts/prefabs/spices","title":"Spices","description":"Defines and configures spice prefabs for use as stackable, floatable inventory items.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spices"},{"id":"game-scripts/prefabs/wagstaff_tools","title":"Wagstaff Tools","description":"Creates lightweight, eroding tool prefabs with toggleable lighting, used for special characters in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagstaff_tools"},{"id":"game-scripts/prefabs/wereitems","title":"Wereitems","description":"Defines prefabs for were-beast-specific food items (beaver, moose, goose) that behave as hazardous, meat-based consumables with cursed effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wereitems"},{"id":"game-scripts/prefabs/winona_holoitems","title":"Winona Holoitems","description":"Creates and manages networked holographic placeholder prefabs for Winona\'s holographic items, handling visual states, lifecycle, and interaction with inventory components.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/winona_holoitems"},{"id":"game-scripts/prefabs/yotd_boats","title":"Yotd Boats","description":"Defines the data and logic for the Year of the Dragon Boat (YOTD) prefabs in DST, including the boat body, deployable kits, item packs, and AI shadowboat variants.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotd_boats"},{"id":"game-scripts/prefabs/yotr_food","title":"Yotr Food","description":"Defines four configurable food prefabs (carrot roll, moon cake, Moon Jelly, and dango) with custom nutritional and perishability values for Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/yotr_food"}],"unlisted":false}}')}}]);